+        assert!((state[0] - 0.25).abs() < 0.01);
+        assert!((state[1] - 2.5).abs() < 0.01);
+        assert!(state[2] > 0.0); // variance > 0
+        assert!((state[3] - 0.5).abs() < 0.001);
+    }
+
+    #[test]
+    fn test_vec_distance() {
