+        // Emit amplitude periodically.
+        if self.frame_count % AMPLITUDE_EMIT_INTERVAL == 0 {
+            unsafe {
+                EVENTS[n_events] = (EVENT_HYPOTHESIS_AMPLITUDE, winner_prob);
