+            // Dampen active hypotheses.
+            mask[Hypothesis::Exercising as usize] = ORACLE_DAMPEN;
+            mask[Hypothesis::MovingLeft as usize] = ORACLE_DAMPEN;
+            mask[Hypothesis::MovingRight as usize] = ORACLE_DAMPEN;
