+    /// Grover diffusion operator: reflect amplitudes about the mean.
+    ///   a_i = 2 * mean(a) - a_i
+    fn grover_diffusion(&mut self) {
+        let mut sum = 0.0f32;
+        for i in 0..N_HYPO {
+            sum += self.amplitudes[i];
+        }
+        let mean = sum / (N_HYPO as f32);
