+        for i in 0..N_HYPO {
+            self.amplitudes[i] = 2.0 * mean - self.amplitudes[i];
+            // Clamp to prevent negative amplitudes (which have no physical meaning
+            // in this classical approximation).
+            if self.amplitudes[i] < 0.0 {
+                self.amplitudes[i] = 0.0;
+            }
+        }
+    }
