+/// Sliced Wasserstein motion detector.
+pub struct OptimalTransportDetector {
+    prev_amps: [f32; MAX_SC],
+    smoothed_dist: f32,
+    smoothed_var: f32,
+    prev_var: f32,
+    initialized: bool,
+    frame_count: u32,
+    shift_streak: u8,
+    subtle_streak: u8,
+}
