+    fn w1_sorted(a: &[f32], b: &[f32], n: usize) -> f32 {
+        if n == 0 { return 0.0; }
+        let mut s = 0.0f32;
+        let mut i = 0; while i < n { s += fabsf(a[i] - b[i]); i += 1; }
+        s / n as f32
+    }
